// Tests de utmp — parser de registros de login de Linux (utmp/wtmp/btmp).
//
// Verificación con ORÁCULO horneada: el fixture son los **primeros 10 registros de
// un /var/log/wtmp real** (WSL), cruzados byte-a-byte contra `utmpdump` (util-linux)
// durante el desarrollo. Se embebe en base64 para que `npm test` corra offline.
// Los casos de manipulación se construyen mutando ese fixture.
//
// Oráculo utmpdump (columnas: type pid id user line host addr time):
//   [2] [00000] [~~  ] [reboot ] [~    ] [6.6.87.2-microsoft-standard-WSL2] [0.0.0.0] [..18:57:19,028211]
//   [5] [00199] [cons] [       ] [console] ...
//   [7] [00217] [1   ] [dust115] [pts/1] ...

import { test } from 'node:test';
import assert from 'node:assert/strict';
import { utmp as U } from '../src/tools/utmp.js';

const B64 = "";
const base = () => new Uint8Array(Buffer.from(B64, 'base64'));

test('parse: 10 registros, struct 384 B', () => {
  const p = U.parse(base());
  assert.equal(p.recSize, 384);
  assert.equal(p.total, 10);
  assert.equal(p.trailing, 0);
});

test('registro 0: reboot (BOOT_TIME) vs utmpdump', () => {
  const r = U.parse(base()).records[0];
  assert.equal(r.type, 2);
  assert.equal(r.typeName, 'BOOT_TIME');
  assert.equal(r.pid, 0);
  assert.equal(r.id, '~~');
  assert.equal(r.user, 'reboot');
  assert.equal(r.line, '~');
  assert.equal(r.host, '6.6.87.2-microsoft-standard-WSL2');
  assert.equal(r.addr, '0.0.0.0');
  assert.equal(r.time, '2026-04-01T18:57:19.028211Z'); // ↔ utmpdump ..18:57:19,028211
});

test('registro 5: login de usuario (USER_PROCESS) vs utmpdump', () => {
  const r = U.parse(base()).records[5];
  assert.equal(r.type, 7);
  assert.equal(r.typeName, 'USER_PROCESS');
  assert.equal(r.pid, 217);
  assert.equal(r.user, 'dust115');
  assert.equal(r.line, 'pts/1');
  assert.equal(r.time, '2026-04-01T18:57:28.448251Z');
});

test('stats: tipos, reboots, usuarios', () => {
  const s = U.parse(base()).stats;
  assert.equal(s.reboots, 1);            // 1 BOOT_TIME
  assert.ok(s.users.includes('dust115'));
  assert.equal(s.byType.USER_PROCESS, 2);
  assert.equal(s.byType.DEAD_PROCESS, 3);
});

test('benigno: sin falsos positivos de manipulación', () => {
  assert.equal(U.parse(base()).anomalies.length, 0);
});

test('manipulación: registro blanqueado entre válidos → detectado', () => {
  const b = base();
  // blanquear el registro idx 5 (rodeado de válidos 4 y 6) — edición quirúrgica de wtmp
  for (let i = 5 * U.REC; i < 6 * U.REC; i++) b[i] = 0;
  const an = U.parse(b).anomalies;
  assert.ok(an.some(a => a.idx === 5 && /vac[ií]o/.test(a.kind)), 'debe marcar el registro 5 blanqueado');
});

test('manipulación: timestamp fuera de orden → detectado', () => {
  const b = base();
  // poner el tvSec del registro 6 muy por debajo del del 5 (inserción/edición)
  const dv = new DataView(b.buffer);
  dv.setInt32(6 * U.REC + 340, 1000000000, true); // 2001, mucho antes que 2026
  const an = U.parse(b).anomalies;
  assert.ok(an.some(a => a.idx === 6 && /orden/.test(a.kind)), 'debe marcar el timestamp retrocedido');
});

test('addr: IPv4 y IPv6', () => {
  const b = new Uint8Array(16);
  b[0] = 192; b[1] = 168; b[2] = 1; b[3] = 10; // IPv4 en addr[0], resto 0
  assert.equal(U.addr(b, 0), '192.168.1.10');
  const v6 = new Uint8Array(16);
  v6[0] = 0x20; v6[1] = 0x01; v6[2] = 0x0d; v6[3] = 0xb8; v6[15] = 1;
  assert.equal(U.addr(v6, 0), '2001:db8::1');
});

test('archivo no múltiplo de 384 → reporta cola sobrante', () => {
  const b = base();
  const trunc = b.slice(0, 5 * U.REC + 100);
  const p = U.parse(trunc);
  assert.equal(p.total, 5);
  assert.equal(p.trailing, 100);
});
